code.C++:
# cook your dish here
n = int(input())
for i in range(n):
    S, X, Y, Z = [int(x) for x in input().split()]
    if(X + Y + Z <= S):
        print(0)
    elif(Z + min(X, Y) > S):
        print(2)
    else:
        print(1)

